import Mathlib

open List

def mkOps : List ((ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ) :=
  let incI : (ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ := λ (i,j,c) => (i+1, j, c)
  let setJ3 : (ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ := λ (i,j,c) => (i, 3, c)
  let decrJ : (ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ := λ (i,j,c) => (i, j-1, c)
  let incC : (ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ := λ (i,j,c) => (i, j, c+1)
  let incJ2 : (ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ := λ (i,j,c) => (i, j+2, c)
  let innerOps : List ((ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ) :=
    List.join (List.replicate 9 [decrJ, incC, incJ2])
  let outerBlock : List ((ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ) := [setJ3] ++ innerOps ++ [incI]
  let outerOps : List ((ℤ × ℤ × ℤ) → ℤ × ℤ × ℤ) :=
    List.join (List.replicate 10 outerBlock)
  outerOps

def allStates : List (ℤ × ℤ × ℤ) :=
  let init : ℤ × ℤ × ℤ := (0, 0, 0)
  let ops := mkOps
  List.scanl (fun s op => op s) init ops

theorem no_overflow : ∀ s ∈ allStates,
  -2147483648 ≤ s.1 ∧ s.1 ≤ 2147483647 ∧
  -2147483648 ≤ s.2.1 ∧ s.2.1 ≤ 2147483647 ∧
  -2147483648 ≤ s.2.2 ∧ s.2.2 ≤ 2147483647 := by
  native_decide

