import Mathlib

def wrap (x : ℤ) : ℤ :=
  let r := x % (2^32 : ℤ)
  if r ≥ (2^31 : ℤ) then r - (2^32 : ℤ) else r

def step (x y : ℤ) : ℤ × ℤ := (wrap (x + y), wrap ((-2)*y - 1))

def iterate : ℕ → ℤ × ℤ → ℤ × ℤ
  | 0, s => s
  | n+1, s => iterate n (step s.1 s.2)

def initial : ℤ × ℤ := (0, 10000)

-- after 10000 iterations x is still non‑negative
theorem non_termination_witness : (iterate 10000 initial).1 ≥ 0 := by
  native_decide

